mapper.select:
SELECT u.userId, u.username, u.`name`, CASE WHEN LENGTH(u.tel) > 7 THEN CONCAT(LEFT(u.tel, 3), '****', RIGHT(u.tel, 4)) ELSE u.tel END AS tel, u.email, u.avatar, u.state, u.isAdmin, u.authRoleId, ar.authRoleName, u.loginIp, u.loginTime, u.createTime, u.updateTime, ( SELECT COUNT(*) FROM sys_device d WHERE d.userId = u.userId ) AS totalDevice, ( SELECT COUNT(*) FROM sys_message m WHERE m.userId = u.userId AND m.state = '1' ) AS totalMessage, ( SELECT COUNT(*) FROM sys_device d WHERE d.userId = u.userId AND d.state = '1' ) AS aliveNumber FROM sys_user u LEFT JOIN sys_auth_role ar ON ar.authRoleId = u.authRoleId WHERE 1 = 1
AND u.email = #{email}
AND u.tel = #{tel}
AND u.name LIKE CONCAT('%', #{name}, '%')
AND u.isAdmin = #{isAdmin}
AND u.authRoleId = #{authRoleId}
ORDER BY u.createTime DESC
